head.b:skin:
/*
-----------------------------------------------
Blogger Template Style
Name:		Minibox
Designer:	James William
URL:		www.2600degrees.com
Date:		26 May 2008
Based on:	Minima
By:			Douglas Bowman
Of:			www.stopdesign.com
----------------------------------------------- */



/* Variable definitions
   ====================
   <Variable name="bgcolor" description="Page Background Color"
             type="color" default="#135" value="#ffffff">
   <Variable name="textcolor" description="Text Color"
             type="color" default="#ccc" value="#323D74">
   <Variable name="linkcolor" description="Link Color"
             type="color" default="#9bd" value="#A73560">
   <Variable name="pagetitlecolor" description="Title Color"
             type="color" default="#eee" value="#102A89">
   <Variable name="descriptioncolor" description="Blog Description Color"
             type="color" default="#79b" value="#3249A1">
   <Variable name="titlecolor" description="Post Title Color"
             type="color" default="#fc6" value="#1E3AA1">
   <Variable name="bordercolor" description="Border Color"
             type="color" default="#468" value="#C0B2CB">
   <Variable name="sidebarcolor" description="Sidebar Title Color"
             type="color" default="#579" value="#9C89AA">
   <Variable name="sidebartextcolor" description="Sidebar Text Color"
             type="color" default="#ccc" value="#8E8AA3">
   <Variable name="visitedlinkcolor" description="Visited Link Color"
             type="color" default="#a7a" value="#BB6C8A">
   <Variable name="bodyfont" description="Text Font"
             type="font" default="normal normal 100% Verdana" value="normal normal 100% Verdana">
   <Variable name="headerfont" description="Sidebar Title Font"
             type="font"
             default="normal bold 78% Arial" value="normal bold 78% Arial">
   <Variable name="pagetitlefont" description="Blog Title Font"
             type="font"
             default="normal bold 200% 'Trebuchet MS',Trebuchet,Verdana,Sans-serif" value="normal bold 200% 'Trebuchet MS',Trebuchet,Verdana,Sans-serif">
   <Variable name="descriptionfont" description="Blog Description Font"
             type="font"
             default="normal normal 100% Arial" value="normal normal 100% Arial">
   <Variable name="postfooterfont" description="Post Footer Font"
             type="font"
             default="normal normal 78% Verdana" value="normal normal 78% Verdana">
*/


/*  my css
------------------------------------*/
#navbar-iframe {  display: none !important; } 

.tabs-inner .section:first-child { display:none; }

.post-timestamp { display:block; clear:both; padding:bottom: 30px; border-top: 1px dotted $bordercolor; padding-top: 5px; font-size:80%; margin-top10px;}
.post-labels {display:block; clear:both; padding:top: 30px; border-bottom: 1px dotted $bordercolor; padding-bottom: 5px;  margin-bottom:20px; font-size:80%;}

#PageList1 {display:none;}


body {

   background: white url(http://futaichigo.files.wordpress.com/2010/11/cyou-2col2.png) top center repeat-y;
   background-attachment:fixed;

  	margin:0;
  	color:$textcolor;
  	font: x-small $bodyfont;
  	font-size/* */:/**/small;
  	font-size: /**/small;
  	text-align: left;
  	}

a:link {
  	color:$linkcolor;
  	text-decoration:none;
  	}

a:visited {
  	color:$visitedlinkcolor;
  	text-decoration:none;
  	}

a:hover {
  	color:$linkcolor;
  	text-decoration:underline;
	}

a img {
  	border-width:0;
  	}

/* Header
-----------------------------------------------
 */

#header-wrapper {
  background: transparent url(http://futaichigo.files.wordpress.com/2010/11/cyou-top.png) top center no-repeat;
height: 120px;
    padding-top:30px;
  	width:958px;
  	margin:0 auto 10px;
  	border:0px solid $bordercolor;
  	}

#header-inner {
  background-position: center;
  margin-left: auto;
  margin-right: auto;
}

#header { 
  	margin: 5px;
  	border: 0px solid $bordercolor;
  	text-align: center;
  	color:$pagetitlecolor;
	}

#header h1 {
  	margin:5px 5px 0;
  	padding:15px 20px .25em;
  	line-height:1.2em;
  	text-transform:none;
  	letter-spacing:.2em;
  	font: $pagetitlefont;
	}

#header a {
  	color:$pagetitlecolor;
  	text-decoration:none;
  	}

#header a:hover {
  	color:$pagetitlecolor;
  	}

#header .description {
  	margin:0 5px 5px;
  	padding:0 20px 15px;
  	max-width:900px;
  	text-transform:none;
  	letter-spacing:.2em;
  	line-height: 1.4em;
  	font: $descriptionfont;
  	color: $descriptioncolor;
 	}

#header img {
  margin-left: auto;
  margin-right: auto;
}

/* Outer-Wrapper
----------------------------------------------- */
#outer-wrapper { /* background:blue; */
  	width: 1000px;
  	margin: 0 auto;
  	padding: 0px 0px;
  	text-align: left;
  	font: $bodyfont;
  	}

#main-wrapper { /* background:green; */
  	width: 643px;
	margin: 0 10px 0;
  	}

#left-sidebar-wrapper { width: 75px; /* background: blue; */ margin-left:-10px; }
#right-sidebar-wrapper {width: 210px; padding-left:10px;}
#main-wrapper, #left-sidebar-wrapper, #right-sidebar-wrapper {
  	border: 0px solid $bordercolor;
  	word-wrap: break-word; /* fix for long text breaking sidebar float in IE */
  	overflow: hidden;     /* fix for long non-text content breaking IE sidebar float */
	}

#left-sidebar-wrapper, #main-wrapper {
  	float: left;
	}

#right-sidebar-wrapper {
  	float: right;
	}

.crosscol {
	text-align: center;
	margin: 10px;
	}

/* Headings
----------------------------------------------- */

h2 {
  	margin:1.5em 0 .75em;
  	font:$headerfont;
  	line-height: 1.4em;
  	text-transform:uppercase;
  	letter-spacing:.2em;
  	color:$sidebarcolor;
	}

/* Posts
-----------------------------------------------
 */
h2.date-header {
  	margin:1.5em 0 .5em;
  	}

.post-wrapper { /* background:green; for whole column of post */
	padding: 5px 10px;
	}

.post {  /* background:blue;   for each single post */
 background: transparent url(http://futaichigo.files.wordpress.com/2010/11/sakura-ball.jpg) bottom right no-repeat;
  	padding: 10px 15px 10px 15px;
  	margin-bottom:40px;
         border: 1px dashed #979CAD;
	 text-align:left;
  	}

.post h3 {
  	margin:.25em 0 0;
  	padding:0 0 4px;
  	font-size:140%;
  	font-weight:normal;
  	line-height:1.4em;
  	color:$titlecolor;
	}

.post h3 a, .post h3 a:visited, .post h3 strong {
  	display:block;
  	text-decoration:none;
  	color:$titlecolor;
  	font-weight:bold;
	}

.post h3 strong, .post h3 a:hover {
  	color:$textcolor;
	}

.post p {
  	margin:0 0 .75em;
  	line-height:1.6em;
	}

.post-footer {
  	margin: .75em 0;
  	color:$sidebarcolor;
  	text-transform:uppercase;
  	letter-spacing:.1em;
  	font: $postfooterfont;
  	line-height: 1.4em;
	}

.comment-link {
  	margin-left:.6em;
  	}

.post img {
  	padding:4px;
  	border:1px solid $bordercolor;
  	max-width:87%;}

.post blockquote {
  	margin:1em 20px;
  	}

.post blockquote p {
  	margin:.75em 0;
  	}

/* Comments
----------------------------------------------- */
#comments h4 {
  	margin:1em 0;
  	font-weight: bold;
  	line-height: 1.4em;
  	text-transform:uppercase;
  	letter-spacing:.2em;
  	color: $sidebarcolor;
  	}

#comments-block {
  	margin:1em 0 1.5em;
  	line-height:1.6em;
  	}

#comments-block .comment-author {
  	margin:.5em 0;
  	}

#comments-block .comment-body {
  	margin:.25em 0 0;
  	}

#comments-block .comment-footer {
  	margin:-.25em 0 2em;
  	line-height: 1.4em;
  	text-transform:uppercase;
  	letter-spacing:.1em;
  	}

#comments-block .comment-body p {
  	margin:0 0 .75em;
  	}

.deleted-comment {
  	font-style:italic;
  	color:gray;
  	}

.feed-links { display:none;
  	clear: both;
  	line-height: 2.5em;
	}

#blog-pager-newer-link {
  	float: right;
 	}

#blog-pager-older-link {
  	float: left;
 	}

#blog-pager {    
  	text-align: center; 
 	}

/* Sidebar Content
----------------------------------------------- */
.left-sidebar-wrapper, .right-sidebar-wrapper  { 
  	color: $sidebartextcolor;
  	line-height: 1.5em;
 	}

.sidebar {
	padding: 5px 10px;
	}

.sidebar ul {
  	list-style:none;
  	margin:0 0 0;
  	padding:0 0 0;
	}

.sidebar li {
  	margin:0;
  	padding:0 0 .25em 15px;
  	text-indent:-15px;
  	line-height:1.5em;
  	}

.sidebar .widget, .main .widget { 
  	border-bottom:0px dotted $bordercolor;
  	margin:0 0 1.5em;
  	padding:0 0 1.5em;
 	}

.main .Blog { 
  	border-bottom-width: 0;
	}

/* Profile 
----------------------------------------------- */
.profile-img { 
  	float: left;
  	margin: 0 5px 5px 0;
  	padding: 4px;
  	border: 1px solid $bordercolor;
	}

.profile-data {
  	margin:0;
  	text-transform:uppercase;
  	letter-spacing:.1em;
  	font: $postfooterfont;
  	color: $sidebarcolor;
  	font-weight: bold;
  	line-height: 1.6em;
	}

.profile-datablock { 
  	margin:.5em 0 .5em;
	}

.profile-textblock { 
  	margin: 0.5em 0;
  	line-height: 1.6em;
	}

.profile-link { 
  	font: $postfooterfont;
  	text-transform: uppercase;
  	letter-spacing: .1em;
	}

/* Footer
----------------------------------------------- */
#footer {
  	width: 958px;
  	clear:both;
  	margin: 0 auto;
  	padding-top:15px;
  	line-height: 1.6em;
  	text-transform:uppercase;
  	letter-spacing:.1em;
  	text-align: center;
	}

.fineprint { display:none;
	font-size: 80%;
	}

/** Page structure tweaks for layout editor wireframe */
body#layout #header { 
  	margin-left: 0px;
  	margin-right: 0px;
}

/* Calendar
----------------------------------------------- */
#blogger_calendar {margin:5px auto 0;width:98%;}
#bcaption {background-color:#fff;padding:2px;margin:10px 0 0;}
#bcaption select {width:100%;}
#bcalendar thead {border-top: 1px dotted #808080;border-bottom: 1px dotted #808080;}
#bcalendar thead tr th {width:20px;text-align:center;padding:2px;font-family:Georgia;font-weight:normal;border-top: 1px dotted #808080;border-bottom: 1px dotted #808080;}
#bcalendar {margin:0 0 0;width:95%;}
#bcalendar tbody tr td {text-align:center;padding:2px;}
#bcalendar tbody tr td a {font-weight:bold;background-color:#EAE2EA;text-decoration:none;}
#bcalendar .firstCell {visibility:visible;}
#bcalendar .emptyCell {visibility:hidden;}
#bcalendar .highlightCell {background-color:#EAE2EA;}
#bcNavigation {width:95%;border-top: 1px dotted #808080;border-bottom: 1px dotted #808080;}
#bcNavigation a {text-decoration:none;}
#bcFootPrev {width:10px;}
#bcFootAll {text-align:center;}
#bcFootNext {width:10px;}
#calendarUl {margin:5px auto 0 !important;}
.listhidden {display:none;}
.listshown {display:inline;}

head.script:
//

var bcLoadingImage = "http://phydeauxredux.googlepages.com/loading-trans.gif";
var bcLoadingMessage = " Loading....";
var bcArchiveNavText = "View Archive";
var bcArchiveNavPrev = '&#9668;';
var bcArchiveNavNext = '&#9658;';
var headDays = ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"];
var headInitial = ["Su","Mo","Tu","We","Th","Fr","Sa"];

// Nothing to configure past this point ----------------------------------
var timeOffset;
var bcBlogID;
var calMonth;
var calDay = 1;
var calYear;
var startIndex;
var callmth;
var bcNav = new Array ();
var bcList = new Array ();

//Initialize Fill Array
var fill = ["","31","28","31","30","31","30","31","31","30","31","30","31"];
function openStatus(){
   document.getElementById('calLoadingStatus').style.display = 'block';
   document.getElementById('calendarDisplay').innerHTML = '';
  }
function closeStatus(){
   document.getElementById('calLoadingStatus').style.display = 'none';
  }
function bcLoadStatus(){
   cls = document.getElementById('calLoadingStatus');
   img = document.createElement('img');
   img.src = bcLoadingImage;
   img.style.verticalAlign = 'middle';
   cls.appendChild(img);
   txt = document.createTextNode(bcLoadingMessage);
   cls.appendChild(txt);
  }
function callArchive(mth,yr,nav){
// Check for Leap Years
  if (((yr % 4 == 0) && (yr % 100 != 0)) || (yr % 400 == 0)) {
      fill[2] = '29';
   }
  else {
      fill[2] = '28';
   }
   calMonth = mth;
   calYear = yr;
   if(mth.charAt(0) == 0){
      calMonth = mth.substring(1);
      }
   callmth = mth;
   bcNavAll = document.getElementById('bcFootAll');
   bcNavPrev = document.getElementById('bcFootPrev');
   bcNavNext = document.getElementById('bcFootNext');
   bcSelect = document.getElementById('bcSelection');
   a = document.createElement('a');
   at = document.createTextNode(bcArchiveNavText);
   a.href = bcNav[nav];
   a.appendChild(at);
   bcNavAll.innerHTML = '';
   bcNavAll.appendChild(a);
   bcNavPrev.innerHTML = '';
   bcNavNext.innerHTML = '';
   if(nav <  bcNav.length -1){
      a = document.createElement('a');
      a.innerHTML = bcArchiveNavPrev;
      bcp = parseInt(nav,10) + 1;
      a.href = bcNav[bcp];
      a.title = 'Previous Archive';
      prevSplit = bcList[bcp].split(',');
      a.onclick = function(){bcSelect.options[bcp].selected = true;openStatus();callArchive(prevSplit[0],prevSplit[1],prevSplit[2]);return false;};
      bcNavPrev.appendChild(a);
      }
   if(nav > 0){
      a = document.createElement('a');
      a.innerHTML = bcArchiveNavNext;
      bcn = parseInt(nav,10) - 1;
      a.href = bcNav[bcn];
      a.title = 'Next Archive';
      nextSplit = bcList[bcn].split(',');
      a.onclick = function(){bcSelect.options[bcn].selected = true;openStatus();callArchive(nextSplit[0],nextSplit[1],nextSplit[2]);return false;};
      bcNavNext.appendChild(a);
     }
   script = document.createElement('script');
   script.src = 'http://www.blogger.com/feeds/'+bcBlogId+'/posts/summary?published-max='+calYear+'-'+callmth+'-'+fill[calMonth]+'T23%3A59%3A59'+timeOffset+'&published-min='+calYear+'-'+callmth+'-01T00%3A00%3A00'+timeOffset+'&max-results=100&orderby=published&alt=json-in-script&callback=cReadArchive';
   document.getElementsByTagName('head')[0].appendChild(script);
}

function cReadArchive(root){
// Check for Leap Years
  if (((calYear % 4 == 0) && (calYear % 100 != 0)) || (calYear % 400 == 0)) {
      fill[2] = '29';
   }
  else {
      fill[2] = '28';
   }
    closeStatus();
    document.getElementById('lastRow').style.display = 'none';
    calDis = document.getElementById('calendarDisplay');
    var feed = root.feed;
    var total = feed.openSearch$totalResults.$t;
    var entries = feed.entry || [];
    var fillDate = new Array();
    var fillTitles = new Array();
    fillTitles.length = 32;
    var ul = document.createElement('ul');
    ul.id = 'calendarUl';
    for (var i = 0; i < feed.entry.length; ++i) {
      var entry = feed.entry[i];
      for (var j = 0; j < entry.link.length; ++j) {
       if (entry.link[j].rel == "alternate") {
       var link = entry.link[j].href;
       }
      }
      var title = entry.title.$t;
      var author = entry.author[0].name.$t;
      var date = entry.published.$t;
      var summary = entry.summary.$t;
      isPublished = date.split('T')[0].split('-')[2];
      if(isPublished.charAt(0) == '0'){
         isPublished = isPublished.substring(1);
         }
      fillDate.push(isPublished);
      if (fillTitles[isPublished]){
          fillTitles[isPublished] = fillTitles[isPublished] + ' | ' + title;
          }
      else {
          fillTitles[isPublished] = title;
          }
      li = document.createElement('li');
      li.style.listType = 'none';
      li.innerHTML = '<a href="'+link+'">'+title+'</a>';
      ul.appendChild(li);

      }
   calDis.appendChild(ul);
   var val1 = parseInt(calDay, 10)
   var valxx = parseInt(calMonth, 10);
   var val2 = valxx - 1;
   var val3 = parseInt(calYear, 10);
   var firstCalDay = new Date(val3,val2,1);
   var val0 = firstCalDay.getDay();
   startIndex = val0 + 1;
  var dayCount = 1;
  for (x =1; x < 38; x++){
      var cell = document.getElementById('cell'+x);
      if( x < startIndex){
          cell.innerHTML = ' ';
          cell.className = 'firstCell';
         }
      if( x >= startIndex){
          cell.innerHTML = dayCount;
          cell.className = 'filledCell';
          for(p = 0; p < fillDate.length; p++){
              if(dayCount == fillDate[p]){
                  if(fillDate[p].length == 1){
                     fillURL = '0'+fillDate[p];
                     }
                  else {
                     fillURL = fillDate[p];
                     }
                  cell.className = 'highlightCell';
                  cell.innerHTML = '<a href="/search?updated-max='+calYear+'-'+callmth+'-'+fillURL+'T23%3A59%3A59'+timeOffset+'&updated-min='+calYear+'-'+callmth+'-'+fillURL+'T00%3A00%3A00'+timeOffset+'" title="'+fillTitles[fillDate[p]].replace(/"/g,'\'')+'">'+dayCount+'</a>';
                 }
              }
          if( dayCount > fill[valxx]){
             cell.innerHTML = ' ';
             cell.className = 'emptyCell';  
             }
          dayCount++;  
         }
      }
    visTotal = parseInt(startIndex) + parseInt(fill[valxx]) -1;
    if(visTotal >35){
        document.getElementById('lastRow').style.display = '';
       }
  }

function initCal(){
   document.getElementById('blogger_calendar').style.display = 'block';
   var bcInit = document.getElementById('bloggerCalendarList').getElementsByTagName('a');
   var bcCount = document.getElementById('bloggerCalendarList').getElementsByTagName('li');
   document.getElementById('bloggerCalendarList').style.display = 'none';
   calHead = document.getElementById('bcHead');
   tr = document.createElement('tr');
   for(t = 0; t < 7; t++){
       th = document.createElement('th');
       th.abbr = headDays[t];
       scope = 'col';
       th.title = headDays[t];
       th.innerHTML = headInitial[t];
       tr.appendChild(th);
      }
   calHead.appendChild(tr);
  for (x = 0; x <bcInit.length;x++){
     var stripYear= bcInit[x].href.split('_')[0].split('/')[3];
     var stripMonth = bcInit[x].href.split('_')[1];
     bcList.push(stripMonth + ','+ stripYear + ',' + x);
     bcNav.push(bcInit[x].href);
     }
  var sel = document.createElement('select');
  sel.id = 'bcSelection';
  sel.onchange = function(){var cSend = this.options[this.selectedIndex].value.split(',');openStatus();callArchive(cSend[0],cSend[1],cSend[2]);};
  q = 0;
  for (r = 0; r <bcList.length; r++){
       var selText = bcInit[r].innerHTML;
       var selCount = bcCount[r].innerHTML.split('> (')[1];
       var selValue = bcList[r];
       sel.options[q] = new Option(selText + ' ('+selCount,selValue);
       q++
       }                    
   document.getElementById('bcaption').appendChild(sel);
   var m = bcList[0].split(',')[0];
   var y = bcList[0].split(',')[1];
   callArchive(m,y,'0');
 }

function timezoneSet(root){
   var feed = root.feed;
   var updated = feed.updated.$t;
   var id = feed.id.$t;
   bcBlogId = id.split('blog-')[1];
   upLength = updated.length;
   if(updated.charAt(upLength-1) == "Z"){timeOffset = "+00:00";}
   else {timeOffset = updated.substring(upLength-6,upLength);}
   timeOffset = encodeURIComponent(timeOffset);
}

//

function togglecomments (postid) {
var whichpost = document.getElementById(postid);
if (whichpost.className=="listshown") { whichpost.className="listhidden"; } else { whichpost.className="listshown"; }
}

